const userPhone = $('📱 WhatsApp Trigger').first().json.messages[0].from;
const evolutionApiKey = 'BB6FE9B78839-47F4-8F7D-14C9AC172F62';
const evolutionUrl = 'https://evolution-api-6vt4.srv1720387.hstgr.cloud';
const supabaseUrl = 'https://doidanwuijcfyaxrgavp.supabase.co';
const supabaseAnonKey = 'sb_publishable_5zgaTIMia5OGYPOqIwkEkA_agKsP1Ox';
const facturaId = query.factura_id || '';

try {
  const searchVal = facturaId.replace('F-', '').toUpperCase();
  const dbRes = await fetch(`${supabaseUrl}/rest/v1/invoices?id=ilike.*${searchVal}&select=id,client_name,total`, {
    method: 'GET',
    headers: {
      'apikey': supabaseAnonKey,
      'Authorization': `Bearer ${supabaseAnonKey}`,
      'Content-Type': 'application/json'
    }
  });

  if (!dbRes.ok) throw new Error('No se pudo conectar con la base de datos de Supabase.');
  const invoices = await dbRes.json();

  if (!invoices || invoices.length === 0) {
    return { success: false, message: `No encontré ninguna factura que coincida con el código ${facturaId}.` };
  }

  const invoice = invoices[0];
  const pdfUrl = `${supabaseUrl}/storage/v1/object/public/facturas-pdf/${invoice.id}.pdf`;

  await fetch(`${evolutionUrl}/message/sendMedia/GestiBot`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'apikey': evolutionApiKey
    },
    body: JSON.stringify({
      number: userPhone,
      medias: [
        {
          media: pdfUrl,
          fileName: `factura-${facturaId.toUpperCase()}.pdf`,
          mediaType: "document",
          caption: `Aquí tienes la factura ${facturaId.toUpperCase()} en formato PDF 📄` 
        }
      ]
    })
  });
  return { success: true, message: `Factura ${facturaId.toUpperCase()} enviada con éxito en PDF por WhatsApp.` };
} catch (error) {
  return { success: false, error: error.message };
}

