const userPhone = $('📱 WhatsApp Trigger').first().json.messages[0].from;
const evolutionApiKey = 'BB6FE9B78839-47F4-8F7D-14C9AC172F62';
const evolutionUrl = 'https://evolution-api-6vt4.srv1720387.hstgr.cloud';
const supabaseUrl = 'https://doidanwuijcfyaxrgavp.supabase.co';
const supabaseAnonKey = 'sb_publishable_5zgaTIMia5OGYPOqIwkEkA_agKsP1Ox';

const cliente = query.cliente_nombre || 'Cliente';
const producto = query.producto || 'Servicio';
const monto = query.monto || 10000;

try {
  const edgeRes = await fetch(`${supabaseUrl}/functions/v1/crear-factura-bot`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${supabaseAnonKey}`,
      'apikey': supabaseAnonKey
    },
    body: JSON.stringify({
      client_name: cliente,
      product_name: producto,
      amount: monto,
      user_phone: userPhone
    })
  });

  if (!edgeRes.ok) {
    const errText = await edgeRes.text();
    throw new Error(`Error en Edge Function: ${errText}`);
  }

  const resJson = await edgeRes.json();
  const pdfUrl = resJson.pdf_url;
  const facturaNo = resJson.invoice_number;

  if (pdfUrl) {
    await fetch(`${evolutionUrl}/message/sendMedia/GestiBot`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': evolutionApiKey
      },
      body: JSON.stringify({
        number: userPhone,
        medias: [
          {
            media: pdfUrl,
            fileName: `factura-${facturaNo}.pdf`,
            mediaType: "document",
            caption: `Factura ${facturaNo} generada por venta de ${producto} a ${cliente} ($${monto}) 📄` 
          }
        ]
      })
    });
  }
  return { success: true, message: resJson.message };
} catch (error) {
  return { success: false, error: error.message };
}

